patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -1,7 +1,7 @@
 module mux_8bit(
   input [7:0] a, b, c, d,
   input [1:0] sel,
   output reg [7:0] out
 );

-  always @(a or b)
+  always @(a or b or c or d or sel)
     case(sel)
       2'b00: out = a;
       2'b01: out = b;

before_code:
module mux_8bit(
  input [7:0] a, b, c, d,
  input [1:0] sel,
  output reg [7:0] out
);

  always @(a or b)
    case(sel)
      2'b00: out = a;
      2'b01: out = b;
      2'b10: out = c;
      2'b11: out = d;
    endcase

endmodule

after_code:
module mux_8bit(
  input [7:0] a, b, c, d,
  input [1:0] sel,
  output reg [7:0] out
);

  always @(a or b or c or d or sel)
    case(sel)
      2'b00: out = a;
      2'b01: out = b;
      2'b10: out = c;
      2'b11: out = d;
    endcase

endmodule
